package com.example.cradlerbacdemo;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;

@SpringBootApplication
public class CradleRbacDemoApplication {
    public static void main(String[] args) {
        SpringApplication.run(CradleRbacDemoApplication.class, args);
    }
}

package com.example.cradlerbacdemo.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.core.userdetails.User;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.provisioning.InMemoryUserDetailsManager;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableMethodSecurity(prePostEnabled = true)
public class SecurityConfig {

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder();
    }

    @Bean
    public UserDetailsService users(PasswordEncoder passwordEncoder) {
        // 建立三個範例使用者：admin, manager, user
        UserDetails admin = User.withUsername("alice.admin")
                .password(passwordEncoder.encode("adminpass"))
                .roles("ADMIN") // ROLE_ADMIN
                .authorities("USER:CREATE", "USER:DELETE", "ORDER:MANAGE")
                .build();

        UserDetails manager = User.withUsername("bob.manager")
                .password(passwordEncoder.encode("managerpass"))
                .roles("MANAGER")
                .authorities("ORDER:MANAGE", "REPORT:VIEW")
                .build();

        UserDetails user = User.withUsername("carol.user")
                .password(passwordEncoder.encode("userpass"))
                .roles("USER")
                .authorities("PROFILE:VIEW")
                .build();

        return new InMemoryUserDetailsManager(admin, manager, user);
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.disable())
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/public/**", "/actuator/health").permitAll()
                .anyRequest().authenticated()
            )
            .httpBasic();

        return http.build();
    }
}

package com.example.cradlerbacdemo.controller;

import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/admin")
public class AdminController {

    // 只有 ROLE_ADMIN 或具備 USER:CREATE 權限的使用者
    @PreAuthorize("hasRole('ADMIN') or hasAuthority('USER:CREATE')")
    @PostMapping("/create-user")
    public String createUser() {
        return "[admin] 建立使用者：成功（模擬）";
    }

    // 只有 ROLE_ADMIN 且具備 USER:DELETE 權限
    @PreAuthorize("hasRole('ADMIN') and hasAuthority('USER:DELETE')")
    @PostMapping("/delete-user")
    public String deleteUser() {
        return "[admin] 刪除使用者：成功（模擬）";
    }
}

package com.example.cradlerbacdemo.controller;

import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/manager")
public class ManagerController {

    // 需要 ORDER:MANAGE 權限或 ROLE_MANAGER
    @PreAuthorize("hasAuthority('ORDER:MANAGE') or hasRole('MANAGER')")
    @PostMapping("/process-order")
    public String processOrder() {
        return "[manager] 處理訂單：成功（模擬）";
    }

    // 報表檢視，需要 REPORT:VIEW 權限
    @PreAuthorize("hasAuthority('REPORT:VIEW')")
    @GetMapping("/view-report")
    public String viewReport() {
        return "[manager] 檢視報表：成功（模擬）";
    }
}

package com.example.cradlerbacdemo.controller;

import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/user")
public class UserController {

    // 公開可存取
    @GetMapping("/public-info")
    public String publicInfo() {
        return "[public] 這是公開資訊";
    }

    // 需要已驗證使用者
    @GetMapping("/profile")
    public String profile() {
        return "[user] 這是使用者自己的個人資料（模擬）";
    }

    // 使用自訂權限檢查
    @PreAuthorize("hasAuthority('PROFILE:VIEW') or hasRole('ADMIN')")
    @GetMapping("/private-profile")
    public String privateProfile() {
        return "[user] 私密個人資料：需要 PROFILE:VIEW 權限";
    }
}
